import{_ as o,c as l,o as t,ag as i}from"./chunks/framework.DK1-H3E1.js";const p=JSON.parse('{"title":"思维链推理（Chain-of-Thought）入门","description":"","frontmatter":{"order":17},"headers":[],"relativePath":"ai/chain-of-thought-reasoning.md","filePath":"ai/chain-of-thought-reasoning.md","lastUpdated":1772197851000}'),e={name:"ai/chain-of-thought-reasoning.md"};function r(h,a,n,s,c,u){return t(),l("div",null,a[0]||(a[0]=[i('<h1 id="思维链推理-chain-of-thought-入门" tabindex="-1">思维链推理（Chain-of-Thought）入门 <a class="header-anchor" href="#思维链推理-chain-of-thought-入门" aria-label="Permalink to &quot;思维链推理（Chain-of-Thought）入门&quot;">​</a></h1><blockquote><p>📅 主题：让模型“先思考，再作答”的提示与工程实践</p></blockquote><h2 id="一、什么是思维链推理" tabindex="-1">一、什么是思维链推理 <a class="header-anchor" href="#一、什么是思维链推理" aria-label="Permalink to &quot;一、什么是思维链推理&quot;">​</a></h2><p><strong>思维链推理（Chain-of-Thought, CoT）</strong> 指的是：<br> 在回答复杂问题时，引导模型先给出中间推理步骤，再给出最终答案。</p><p>直观理解：</p><ul><li>普通回答：直接给结论</li><li>CoT 回答：问题拆解 → 逐步推理 → 最终结论</li></ul><p>它特别适用于：</p><ul><li>多步骤数学题</li><li>逻辑推理</li><li>规则判断</li><li>需要解释过程的问答任务</li></ul><hr><h2 id="二、为什么-cot-有效" tabindex="-1">二、为什么 CoT 有效 <a class="header-anchor" href="#二、为什么-cot-有效" aria-label="Permalink to &quot;二、为什么 CoT 有效&quot;">​</a></h2><p>复杂任务失败的常见原因是“跳步推理”：模型直接猜结论，忽略关键中间约束。<br> CoT 的价值在于把推理显式化：</p><ol><li>降低一步到位猜测的概率</li><li>让模型在每一步对齐问题条件</li><li>提升复杂任务的稳定性与可解释性</li></ol><p>可以把 CoT 理解为“给模型一个可执行的思考轨道”。</p><hr><h2 id="三、常见-cot-方式" tabindex="-1">三、常见 CoT 方式 <a class="header-anchor" href="#三、常见-cot-方式" aria-label="Permalink to &quot;三、常见 CoT 方式&quot;">​</a></h2><h2 id="_3-1-zero-shot-cot" tabindex="-1">3.1 Zero-shot CoT <a class="header-anchor" href="#_3-1-zero-shot-cot" aria-label="Permalink to &quot;3.1 Zero-shot CoT&quot;">​</a></h2><p>不提供示例，只在提示里要求模型分步思考，例如：</p><ul><li>“请一步一步分析后再给出答案”</li><li>“先列出推理过程，再输出结论”</li></ul><p>优点：简单、低成本。<br> 局限：在复杂领域任务上不一定稳定。</p><h2 id="_3-2-few-shot-cot" tabindex="-1">3.2 Few-shot CoT <a class="header-anchor" href="#_3-2-few-shot-cot" aria-label="Permalink to &quot;3.2 Few-shot CoT&quot;">​</a></h2><p>提供若干“问题 + 推理步骤 + 答案”示例，让模型模仿该推理风格。</p><p>优点：格式和推理路径更可控。<br> 局限：占用更多上下文 token，需要高质量示例。</p><h2 id="_3-3-structured-cot-结构化思维链" tabindex="-1">3.3 Structured CoT（结构化思维链） <a class="header-anchor" href="#_3-3-structured-cot-结构化思维链" aria-label="Permalink to &quot;3.3 Structured CoT（结构化思维链）&quot;">​</a></h2><p>把推理过程固定成结构，例如：</p><ol><li>问题拆解</li><li>约束提取</li><li>方案比较</li><li>结论输出</li></ol><p>这类方式在工程里更容易做自动评估与解析。</p><hr><h2 id="四、cot-与-react、tot-的关系" tabindex="-1">四、CoT 与 ReAct、ToT 的关系 <a class="header-anchor" href="#四、cot-与-react、tot-的关系" aria-label="Permalink to &quot;四、CoT 与 ReAct、ToT 的关系&quot;">​</a></h2><p>这些方法常被一起讨论，但目标不同：</p><ul><li><strong>CoT</strong>：强调“推理过程显式化”</li><li><strong>ReAct</strong>：推理 + 行动交替（思考后调用工具，再观察结果）</li><li><strong>ToT（Tree of Thoughts）</strong>：并行探索多条思路并择优</li></ul><p>可以理解为：</p><ul><li>CoT 是基础形态</li><li>ReAct / ToT 是更强的“推理 + 决策”扩展</li></ul><hr><h2 id="五、工程实践中的关键点" tabindex="-1">五、工程实践中的关键点 <a class="header-anchor" href="#五、工程实践中的关键点" aria-label="Permalink to &quot;五、工程实践中的关键点&quot;">​</a></h2><h2 id="_5-1-何时用-cot" tabindex="-1">5.1 何时用 CoT <a class="header-anchor" href="#_5-1-何时用-cot" aria-label="Permalink to &quot;5.1 何时用 CoT&quot;">​</a></h2><p>建议用于：</p><ul><li>需要多步骤推理的问题</li><li>错误代价高、需要可解释过程的场景</li><li>需要结果自检或过程审计的任务</li></ul><p>不建议用于：</p><ul><li>纯事实查询（会增加延迟和 token 成本）</li><li>简单分类/抽取（步骤可能冗余）</li></ul><h2 id="_5-2-结果输出与过程输出分离" tabindex="-1">5.2 结果输出与过程输出分离 <a class="header-anchor" href="#_5-2-结果输出与过程输出分离" aria-label="Permalink to &quot;5.2 结果输出与过程输出分离&quot;">​</a></h2><p>很多业务只希望返回结论，不希望前端展示长推理。常见做法：</p><ul><li>模型内部生成推理</li><li>最终只输出结构化结论（例如 JSON 字段）</li><li>推理过程仅用于日志或评估</li></ul><h2 id="_5-3-结合检索与工具" tabindex="-1">5.3 结合检索与工具 <a class="header-anchor" href="#_5-3-结合检索与工具" aria-label="Permalink to &quot;5.3 结合检索与工具&quot;">​</a></h2><p>在 RAG/Agent 场景里，CoT 常与外部能力结合：</p><ol><li>先检索证据</li><li>基于证据分步推理</li><li>需要时调用工具验证</li><li>输出结论并给出引用</li></ol><p>这样可减少“看起来合理但无依据”的推理。</p><hr><h2 id="六、cot-常见问题与规避" tabindex="-1">六、CoT 常见问题与规避 <a class="header-anchor" href="#六、cot-常见问题与规避" aria-label="Permalink to &quot;六、CoT 常见问题与规避&quot;">​</a></h2><h3 id="问题-1-推理过程很长但答案仍错" tabindex="-1">问题 1：推理过程很长但答案仍错 <a class="header-anchor" href="#问题-1-推理过程很长但答案仍错" aria-label="Permalink to &quot;问题 1：推理过程很长但答案仍错&quot;">​</a></h3><p>原因：模型可能生成“看似合理”的伪推理。<br> 应对：引入外部验证（规则校验、计算工具、引用检查）。</p><h3 id="问题-2-推理成本高、响应慢" tabindex="-1">问题 2：推理成本高、响应慢 <a class="header-anchor" href="#问题-2-推理成本高、响应慢" aria-label="Permalink to &quot;问题 2：推理成本高、响应慢&quot;">​</a></h3><p>原因：CoT 增加输出 token。<br> 应对：只在复杂任务启用；简单任务走快速路径。</p><h3 id="问题-3-过程暴露不必要信息" tabindex="-1">问题 3：过程暴露不必要信息 <a class="header-anchor" href="#问题-3-过程暴露不必要信息" aria-label="Permalink to &quot;问题 3：过程暴露不必要信息&quot;">​</a></h3><p>原因：完整思维链直接返回给用户。<br> 应对：前后端分离：用户只看结论，过程仅内部使用。</p><h3 id="问题-4-风格不稳定" tabindex="-1">问题 4：风格不稳定 <a class="header-anchor" href="#问题-4-风格不稳定" aria-label="Permalink to &quot;问题 4：风格不稳定&quot;">​</a></h3><p>原因：提示过于模糊。<br> 应对：用结构化模板或 few-shot 示例固定输出格式。</p><hr><h2 id="七、评估-cot-效果的方法" tabindex="-1">七、评估 CoT 效果的方法 <a class="header-anchor" href="#七、评估-cot-效果的方法" aria-label="Permalink to &quot;七、评估 CoT 效果的方法&quot;">​</a></h2><p>不要只看“回答更长了”，建议同时看：</p><ol><li><strong>正确率提升</strong>：复杂题集上的准确率变化</li><li><strong>稳定性</strong>：同类问题多次调用的一致性</li><li><strong>可验证性</strong>：中间步骤是否可被规则/工具验证</li><li><strong>成本与时延</strong>：token 增量是否可接受</li></ol><p>工程上常见做法是 A/B：</p><ul><li>A：普通回答</li><li>B：启用 CoT</li></ul><p>再比较准确率、延迟、成本，决定是否默认开启。</p><hr><h2 id="八、与上下文工程、agent-的配合" tabindex="-1">八、与上下文工程、Agent 的配合 <a class="header-anchor" href="#八、与上下文工程、agent-的配合" aria-label="Permalink to &quot;八、与上下文工程、Agent 的配合&quot;">​</a></h2><ul><li><strong>上下文工程</strong>：决定 CoT 的提示模板和上下文排布（把证据放在问题附近，减少无关干扰）</li><li><strong>RAG</strong>：为 CoT 提供可引用证据，防止“空想推理”</li><li><strong>Agent</strong>：把 CoT 用在“计划、决策、复盘”环节，结合工具调用形成闭环</li></ul><p>在生产环境中，CoT 通常不是单独存在，而是整个推理系统的一部分。</p><hr><h2 id="九、小结" tabindex="-1">九、小结 <a class="header-anchor" href="#九、小结" aria-label="Permalink to &quot;九、小结&quot;">​</a></h2><ol><li>CoT 的核心是“先推理再结论”，对复杂任务更有效。</li><li>Zero-shot CoT 上手快，Few-shot/结构化 CoT 更稳定。</li><li>CoT 不是万能，需结合检索、工具与校验机制。</li><li>实际落地要平衡正确率、稳定性、延迟与成本。</li><li>把 CoT 视为“推理能力放大器”，而不是简单的“回答变长”。</li></ol><p>当你把 CoT 放进可验证、可评估的流程里，它会从“提示技巧”升级为“工程能力”。</p>',71)]))}const T=o(e,[["render",r]]);export{p as __pageData,T as default};
